import React, { useEffect, useState } from "react";
import axios from "axios";

const AdminScreen = () => {
  const [users, setUsers] = useState([]);
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    fetchAll();
  }, []);

  const fetchAll = async () => {
    const usersData = await axios.get("http://localhost:5000/api/users");
    const productsData = await axios.get("http://localhost:5000/api/products");
    const ordersData = await axios.get("http://localhost:5000/api/orders");

    setUsers(usersData.data);
    setProducts(productsData.data);
    setOrders(ordersData.data);
  };

  return (
    <div>
      <h1>Admin Panel</h1>

      <h2>Users</h2>
      {users.map((u) => (
        <p key={u._id}>{u.name} - {u.email}</p>
      ))}

      <h2>Products</h2>
      {products.map((p) => (
        <p key={p._id}>{p.name} - ₹{p.price}</p>
      ))}

      <h2>Orders</h2>
      {orders.map((o) => (
        <p key={o._id}>{o._id} - ₹{o.totalAmount}</p>
      ))}
    </div>
  );
};

export default AdminScreen;
